const topic = $json.topic;
const angle = $json.angle;
const prompt = `COMPLIANCE (India, non-negotiable): no buy/sell/hold, no target price, no multibagger, no guaranteed or assured returns, no return predictions on any security; education and post-facto news only; crypto needs the ASCI disclaimer; no forex promotion. Tu Finplaza ka head writer hai, ek BOLD energetic Indian personal-finance Shorts channel. Ek 35 se 45 second HINGLISH Shorts script likh (Roman-script Hindi mixed with English finance terms jaise credit card, EMI, cashback, interest). TOPIC: ${topic}. ANGLE: ${angle}. Hook pehli line mein, 3 second ke andar land ho. Numbers digits mein jaise ₹12,000 aur 4 percent. Sirf education, koi buy ya sell ya returns ki baat nahi. End mein soft CTA: follow kar weekly card breakdown ke liye. Output ONLY JSON with: script (the spoken VO in Hinglish Roman script, plain sentences, no stage directions), onscreen (array of objects, each with t = approx start seconds and text = a short punchy Hinglish caption or number to show), caption (a Hinglish YouTube Shorts caption with 3 to 5 hashtags).`;
return [{ json: { topic, angle, prompt } }];

const parts = ($json.candidates && $json.candidates[0] && $json.candidates[0].content && $json.candidates[0].content.parts) || [];
const text = parts.map(function (p) { return p.text; }).filter(Boolean).join('') || '{}';
let out = {};
try { out = JSON.parse(text); } catch (e) { const m = text.match(/\{[\s\S]*\}/); out = m ? JSON.parse(m[0]) : { raw: text }; }
const topic = $('Set topic').first().json.topic;
return [{ json: Object.assign({ topic: topic }, out) }];
